SELECT * FROM decision_signals

    AND market = #{market}
    AND stock_code = #{stockCode}
    AND action = #{action}
    AND market_phase = #{marketPhase}
    AND source_type = #{sourceType}
    AND status = #{status}
    AND created_at >= #{createdFrom}
    AND created_at <= #{createdTo}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM decision_signals

    AND market = #{market}
    AND stock_code = #{stockCode}
    AND action = #{action}
    AND market_phase = #{marketPhase}
    AND source_type = #{sourceType}
    AND status = #{status}
    AND created_at >= #{createdFrom}
    AND created_at <= #{createdTo}
